head.script:
/**
 * @event 
 * @name onpageload 
 * @description 화면 초기화
 */
scwin.onpageload = function () { };



/**
 * @event 
 * @name onUdcCompleted 
 * @description UDC 완료
 */
scwin.onUdcCompleted = function () {

    scwin.globalVars();

    let codeOptions = [];

    codeOptions = [
        { grpCd: "FS261", compID: "acb_copCoConfirmClsCd" },
        { grpCd: "FS262", compID: "acb_pchsAdmitClsCd" },
    ];
    $c.data.setCommonCode(codeOptions, () => {
        acb_copCoConfirmClsCd.addItem('전체', '', '', 0);
        acb_copCoConfirmClsCd.setSelectedIndex(0);

        acb_pchsAdmitClsCd.addItem('전체', '', '', 0);
        acb_pchsAdmitClsCd.setSelectedIndex(0);
    });

    codeOptions = [
        {
            method: "getLuxeComboData",
            param1: "WorkImplementEBC",
            param2: "retrivecWrkImpleKndList",
            compID: "acb_wrkImpleKndCd"
        }
    ];
    $c.data.setGauceUtil(codeOptions, () => {
        acb_wrkImpleKndCd.addItem('전체', '', '', 0);
        acb_wrkImpleKndCd.setSelectedIndex(0);
    });

    scwin.f_OnLoad();
};




/**
 * @method 
 * @name globalVars 
 * @description 전역변수선언
 */
scwin.globalVars = function () {

    const loginDTO = $c.data.getMemInfo();  // 공통 세션 변수
    scwin.userClsCd = loginDTO.userClsCd;  // 사용자구분코드(02:협력업체(운송))
    scwin.loginClntNo = loginDTO.clntNo;
    scwin.loginClntNm = loginDTO.clntNm;

    scwin.vCurDate = $c.date.getServerDateTime('yyyyMMdd');  // 서버를 기준으로 현재 날짜 반환
    const yaerMonth = scwin.vCurDate.slice(0, 6);
    scwin.vQryStDt = yaerMonth + "01";  // 조회일자 from(현재 날짜가 포함된 달의 시작 일자)
    scwin.vQryEndDt = yaerMonth + $c.date.getLastDateOfMonth(yaerMonth);  // 조회일자 to(현재 날짜가 포함된 달의 마지막 일자)

};



/**
 * @method 
 * @name f_OnLoad 
 * @description 화면로딩시
 */
scwin.f_OnLoad = function () {

    acb_dtCls.setSelectedIndex(0);  // 일자구분
    scwin.f_SelWrkDt();
    scwin.f_SetDefaultData();
    $c.gus.cfDisableAllBtn();
    $c.gus.cfDisableObjects([ica_allCopCoConfirmDt]);

    // 테스트 데이터
    // ed_pchsClntNo.setValue('124781');
    // dma_wrkDt.set('from', '20080101');
    // dma_wrkDt.set('to', '20081231');

    // ed_pchsClntNo.setValue('528947');
    // ed_wrkDtSt.setValue('20201101');
    // ed_wrkDtEnd.setValue('20260228');

};



/**
 * @method 
 * @name f_SetDefaultData 
 * @description Default Data Setting
 */
scwin.f_SetDefaultData = function () {

    scwin.f_GetConfirmCntTotAmt();  // 건수/총금액 계산

    ed_wrkDtSt.setValue(scwin.vQryStDt);  // 출발일자시작
    ed_wrkDtEnd.setValue(scwin.vQryEndDt);  // 출발일자종료
    ed_copCoConfirmDtSt.setValue(scwin.vQryStDt);  // 확인일자시작
    ed_copCoConfirmDtEnd.setValue(scwin.vQryEndDt);  // 확인일자종료

    acb_copCoConfirmClsCd.setMaxLength(50);
    acb_copCoConfirmClsCd.setSelectedIndex(0);
    acb_pchsAdmitClsCd.setMaxLength(50);
    acb_pchsAdmitClsCd.setSelectedIndex(0);
    acb_wrkImpleKndCd.setSelectedIndex(0)

    if (scwin.userClsCd != "01") {  // 내부사용자가 아니면
        ed_pchsClntNo.setValue(scwin.loginClntNo);
        txt_pchsClntNm.setValue(scwin.loginClntNm);
        ed_pchsClntNo.setDisabled(true);
        txt_pchsClntNm.setDisabled(true);
        img_PopUp1.setDisabled(true);
    } else {
        ed_pchsClntNo.focus();
    };

};



/**
 * @method 
 * @name f_RetrieveWorkImplementLoanChargeList 
 * @description 작업도구임차료목록 조회
 */
scwin.f_RetrieveWorkImplementLoanChargeList = async function () {

    // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
    switch (acb_dtCls.getValue()) {
        case '01': // 작업일자 기준
            if (!await $c.gus.cfValidate([ed_pchsClntNo, ed_wrkDtSt, ed_wrkDtEnd])) {
                return;
            };

            if (!$c.gus.cfIsAfterDate(dma_wrkDt.get('from'), dma_wrkDt.get('to'))) {
                $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
                ed_wrkDtSt.focus();
                return;
            };
            break;

        case '02': // 확인일자 기준
            if (!await $c.gus.cfValidate([ed_pchsClntNo, ed_copCoConfirmDtSt, ed_copCoConfirmDtEnd])) {
                return;
            };

            if (!$c.gus.cfIsAfterDate(dma_copCoConfirmDt.get('from'), dma_copCoConfirmDt.get('to'))) {
                $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
                ed_copCoConfirmDtSt.focus();
                return;
            };
            break;

        default:
            break;
    };


    // 모선과 항차 동시 조회 조건 체크
    if (!$c.gus.cfIsNull(ed_coshipvsslCd.getValue()) || !$c.gus.cfIsNull(ed_coshipPortcnt.getValue())) {
        if ($c.gus.cfIsNull(ed_coshipvsslCd.getValue())) {
            $c.gus.cfAlertMsg("모선를 입력하십시오.");
            ed_coshipvsslCd.focus();
            return;
        } else if ($c.gus.cfIsNull(ed_coshipPortcnt.getValue())) {
            $c.gus.cfAlertMsg("항차를 입력하십시오.");
            ed_coshipPortcnt.focus();
            return;
        };
    };

    // 구분(미확인포함여부/미승인포함여부)- 쿼리문에서 사용
    if (cbx_unconfirmedIncluYn.getValue() == 0 && cbx_unAdmitIncluYn.getValue() == 0) {
        dma_purchaseListQueryConditionDTO.set("incluYn", "N");
    } else {
        dma_purchaseListQueryConditionDTO.set("incluYn", "Y");
    };

    $c.sbm.execute(sbm_purchaseListQueryConditionDTO);

};



/**
 * @method 
 * @name f_Confirm 
 * @description 작업도구 임차료 확인
 */
scwin.f_Confirm = function () {

    // Data 변경 여부 조회
    if (ds_workImplementLoanChargeList.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    };

    // 협력업체확인구분(FS261)이 01:미확인, 03:이의신청, 04:이의거부, 05:이의수용
    let rowData = {};
    let rowCnt = ds_workImplementLoanChargeList.getRowCount();

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_workImplementLoanChargeList.getRowJSON(i);
        if (rowData.chk == "T") {
            if (rowData.copCoConfirmClsCd == "02") {
                $c.gus.cfAlertMsg("이미 확인된 건이 포함되어 있습니다.");
                return;
            };
        };
    };

    // 일괄적용 확인일자
    let allCopCoConfirmDt = ica_allCopCoConfirmDt.getValue();
    if ($c.gus.cfIsNull(allCopCoConfirmDt) || allCopCoConfirmDt == "") {
        allCopCoConfirmDt = scwin.vCurDate;
    };

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_workImplementLoanChargeList.getRowJSON(i);
        if (rowData.chk == "T") {
            rowData.copCoConfirmClsCd = "02";
            rowData.copCoConfirmClsNm = "확인";
            rowData.copCoConfirmDt = allCopCoConfirmDt;  // 일괄적용 확인일자
            rowData.btn = "T";
            rowData.chk = "F";

            ds_workImplementLoanChargeList.setRowJSON(i, rowData, true);
        };
    };

};



/**
 * @method 
 * @name f_ConfirmDtUpdate 
 * @description 작업도구 임차료 확인일자 수정
 */
scwin.f_ConfirmDtUpdate = function () {

    // Data 변경 여부 조회
    if (ds_workImplementLoanChargeList.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    };

    // 협력업체확인구분(FS261)이 02:확인 이면서 매입승인구분(FS262)이 01:미승인, 03:보류
    let rowData = {};
    let rowCnt = ds_workImplementLoanChargeList.getRowCount();

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_workImplementLoanChargeList.getRowJSON(i);

        if (rowData.chk == "T") {
            if (rowData.copCoConfirmClsCd != "02") {
                $c.gus.cfAlertMsg("미확인인 건이 포함되어 있습니다.");
                return;
            };
            if (rowData.pchsAdmitClsCd == "02") {
                $c.gus.cfAlertMsg("이미 동부 승인이 이루어진 건이 포함되어 있습니다.");
                return;
            };
        }
    }

    // 일괄적용 확인일자
    let allCopCoConfirmDt = ica_allCopCoConfirmDt.getValue();
    if ($c.gus.cfIsNull(allCopCoConfirmDt) || allCopCoConfirmDt == "") {
        allCopCoConfirmDt = scwin.vCurDate;
    }

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_workImplementLoanChargeList.getRowJSON(i);

        if (rowData.chk == "T") {
            rowData.copCoConfirmDt = allCopCoConfirmDt;  // 일괄적용 확인일자
            rowData.btn = "T";
            rowData.chk = "F";

            ds_workImplementLoanChargeList.setRowJSON(i, rowData, true);
        };
    };

};



/**
 * @method 
 * @name f_ConfirmCancel 
 * @description 작업도구 임차료 확인 취소
 */
scwin.f_ConfirmCancel = function () {

    // Data 변경 여부 조회
    if (ds_workImplementLoanChargeList.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    };

    // 협력업체확인구분(FS261)이 02:확인 이면서 매입승인구분(FS262)이 01:미승인
    let rowData = {};
    let rowCnt = ds_workImplementLoanChargeList.getRowCount();

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_workImplementLoanChargeList.getRowJSON(i);

        if (rowData.chk == "T") {
            if (rowData.copCoConfirmClsCd != "02") {
                $c.gus.cfAlertMsg("미확인인 건이 포함되어 있습니다.");
                return;
            };
            if (rowData.pchsAdmitClsCd != "01") {
                $c.gus.cfAlertMsg("이미 동부 승인이 이루어진 건이 포함되어 있습니다.");
                return;
            };
        };
    };

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_workImplementLoanChargeList.getRowJSON(i);

        if (rowData.chk == "T") {
            rowData.copCoConfirmClsCd = "01";
            rowData.copCoConfirmClsNm = "미확인";
            rowData.copCoConfirmDt = "";
            rowData.rsltsPic = "";  // 실적담당자
            rowData.btn = "T";
            rowData.chk = "F";

            ds_workImplementLoanChargeList.setRowJSON(i, rowData, true);
        };
    };

};



/**
 * @method 
 * @name f_DissentApply 
 * @description 작업도구 임차료 이의제기
 */
scwin.f_DissentApply = function () {

    // Data 변경 여부 조회
    if (ds_workImplementLoanChargeList.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    };

    // 협력업체확인구분(FS261)이 01:미확인, 04:이의거부, 05:이의수용
    let rowData = {};
    let rowCnt = ds_workImplementLoanChargeList.getRowCount();

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_workImplementLoanChargeList.getRowJSON(i);

        if (rowData.chk == "T") {
            if (["02", "03"].includes(rowData.copCoConfirmClsCd)) {
                $c.gus.cfAlertMsg("확인된 건이 포함되어 있습니다.\n해당건은 먼저 확인취소를 해야 합니다.");
                return;
            };
        };
    };

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_workImplementLoanChargeList.getRowJSON(i);

        if (rowData.chk == "T") {
            rowData.copCoConfirmClsCd = "03";
            rowData.copCoConfirmClsNm = "이의신청";
            rowData.copCoConfirmDt = "";
            rowData.dissent = "이의 내용을 입력하십시오.";
            rowData.btn = "T";
            rowData.chk = "F";

            ds_workImplementLoanChargeList.setRowJSON(i, rowData, true);
        };
    };

};



/**
 * @method 
 * @name f_Cancel 
 * @description 취소
 */
scwin.f_Cancel = function () {

    // Data 변경 여부 조회
    if (ds_workImplementLoanChargeList.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    };

    // 취소할 목록 선택
    let cnt = 0, rowData = {};
    let rowCnt = ds_workImplementLoanChargeList.getRowCount();

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_workImplementLoanChargeList.getRowJSON(i);
        if (rowData.chk == "T") cnt++;
    };

    if (cnt == 0) {
        $c.gus.cfAlertMsg("취소할 목록을 선택하십시오.");
        return;
    }

    // 원래값 복원
    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_workImplementLoanChargeList.getRowJSON(i);

        if (rowData.chk == "T") {
            ds_workImplementLoanChargeList.undoRow(i);  // 해당 DataSet의 Row를 원래값(=Original Data)로 복원
            ds_workImplementLoanChargeList.setCellData(i, "btn", "F");
            ds_workImplementLoanChargeList.setCellData(i, "chk", "F");
        };
    };

    gr_workImplementLoanChargeList.setColumnReadOnly('copCoConfirmDt', true);  // 입력불가

};



/**
 * @method 
 * @name f_Save 
 * @description 저장
 */
scwin.f_Save = async function () {

    // Data 변경 여부 조회
    if (ds_workImplementLoanChargeList.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    };

    // 처리버튼 클릭여부
    let cnt = 0, rowData = {};
    let rowCnt = ds_workImplementLoanChargeList.getRowCount();

    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_workImplementLoanChargeList.getRowJSON(i);
        if (rowData.btn == "T") cnt++;
    };

    if (cnt == 0) {
        $c.gus.cfAlertMsg("처리할 업무을 선택하십시오.");
        return;
    };


    // 확인 날짜입력시 validate 체크
    for (let i = 0; i < rowCnt; i++) {
        rowData = ds_workImplementLoanChargeList.getRowJSON(i);

        if (rowData.btn == "T" && rowData.copCoConfirmClsCd == "02") {
            if ($c.num.isNumber(rowData.copCoConfirmDt)) {
                if (!$c.date.isDate(rowData.copCoConfirmDt, false)) {
                    $c.gus.cfAlertMsg((i + 1) + "번째 데이타에서 확인일자는 'YYYYMMDD' 형식이어야 합니다.");
                    ds_workImplementLoanChargeList.setRowPosition(i);
                    return;
                };
            };

            // 이의신청시 이의처리/보류사유 입력
            if (rowData.copCoConfirmClsCd == "03") {
                if (rowData.dissent.length == 0 || rowData.dissent == null || rowData.dissent == "이의 내용을 입력하십시오.") {
                    $c.gus.cfAlertMsg((i + 1) + "번째 데이타에서 이의처리/보류사유를 입력하십시오.");
                    ds_workImplementLoanChargeList.setRowPosition(i);
                    return;
                };
            };
        };
    };

    // 저장하시겠습니까?
    let retVal = await $c.win.confirm(MSG_CM_CRM_001);
    if (!retVal) return;

    $c.sbm.execute(sbm_saveCooperationCompanyConfirmation);

};



/**
 * @method 
 * @name f_RetrieveDissentApplyHistory 
 * @description 이의신청 이력 수정
 * @param {number} row
 */
scwin.f_RetrieveDissentApplyHistory = function (row) {

    let rowData = ds_workImplementLoanChargeList.getRowJSON(row);

    // 팝업화면에게 key 정보인 오더번호와 매입순번을 넘겨준다.
    let data = {
        "odrNo": rowData.odrNo,  // 오더번호
        "pchsSeq": rowData.pchsSeq,  // 매입순번
    };

    // 이의신청 이력 화면 호출
    let url = '/ui/ds/fs/adjm/fs_102_01_01p.xml';
    let opts = {
        type: 'browserPopup',
        width: '825px',
        height: '520px',
    };

    $c.win.openPopup(url, opts, data);

    // 다시 조회함 
    scwin.f_RetrieveWorkImplementLoanChargeList();

};



/**
 * @method 
 * @name f_GetConfirmCntTotAmt 
 * @description 조회건수/조회총금액, 확인건수/확인총금액 계산
 */
scwin.f_GetConfirmCntTotAmt = function () {

    // 임차료
    let qryCnt = 0;
    let qryTotAmt = 0;
    let rowCnt = ds_workImplementLoanChargeList.getRowCount();

    if (rowCnt > 0) {
        qryCnt = rowCnt;

        let colValArray = ds_workImplementLoanChargeList.getColData('pchsAmt');
        qryTotAmt = colValArray.reduce((preVal, curVal) => {
            return preVal += $c.num.parseInt(curVal);
        }, 0);
    };

    lay_qryCnt.setValue($c.gus.cfInsertComma(qryCnt));
    lay_qryTotAmt.setValue($c.gus.cfInsertComma(qryTotAmt));


    // 매입승인구분이 승인(02)인 경우만 임차료 계산
    let confirmCnt = 0;
    let confirmTotAmt = 0;

    for (let i = 0; i < rowCnt; i++) {
        let rowData = ds_workImplementLoanChargeList.getRowJSON(i);
        if (rowData.copCoConfirmClsCd == "02") {
            confirmTotAmt += $c.num.parseInt(rowData.pchsAmt);
            confirmCnt++;
        };
    };

    lay_confirmCnt.setValue($c.gus.cfInsertComma(confirmCnt));
    lay_confirmTotAmt.setValue($c.gus.cfInsertComma(confirmTotAmt));

};



/**
 * @method 
 * @name f_SelWrkDt 
 * @description 작업일자 선택
 */
scwin.f_SelWrkDt = function () {
    lay_gubun1.show('');
    lay_gubun2.show('');
    lay_gubun3.show('');
    lay_gubun4.show('');
    udc_wrkDt.show('');
    udc_copCoConfirmDt.hide();
};



/**
 * @method 
 * @name f_SelCopCoConfirmDt 
 * @description 확인일자 선택
 */
scwin.f_SelCopCoConfirmDt = function () {
    lay_gubun1.hide();
    lay_gubun2.hide();
    lay_gubun3.hide();
    lay_gubun4.hide();
    udc_wrkDt.hide();
    udc_copCoConfirmDt.show('')
};



/**
 * @method 
 * @name f_RetrieveDissentApplyHistory 
 * @description 엑셀 다운로드
 */
scwin.f_RunExcel = function () {

    let count = ds_workImplementLoanChargeList.getRowCount();
    if (!(count > 0)) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);  // 조회결과가 존재하지 않습니다.
        return;
    };

    let excelName = '작업도구 임차료 내역 확인';

    let options = {
        sheetName: excelName,
        fileName: excelName + ".xlsx",
        startRowIndex: 2,
        useHeaderCheckBoxLabel: true
    };

    let infoArr = [{
        text: excelName,
        rowIndex: 0,
        colSpan: gr_workImplementLoanChargeList.getTotalCol(),
        textAlign: 'center',
        fontSize: '12px',
        fontName: '돋움체',
        color: 'black',
        bgColor: '#ffffff'
    }];

    $c.data.downloadGridViewExcel(gr_workImplementLoanChargeList, options, infoArr);

};




/**
 * @method 
 * @name f_openCommonPopUp 
 * @description 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
 * @param {number} disGubun
 * @param {string} pCode
 * @param {string} pName
 * @param {string} pClose
 * @param {string} pAllSearch
 */
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {

    let comCodeComp, codeNameArray, selectedId;
    let pDispCnt = null, pTitle = null, pWidth = null, pHidden = null,
        pWhere = null, pW = null, pH = null, pTop = null, pLeft = null,
        pExistTF = null, pWtitleSearch = null, pNoDataCloseTF = null;

    switch (disGubun) {
        case 1:
            // 협력회사 팝업
            comCodeComp = udc_pchsClnt;
            selectedId = 'retrieveClntList';
            codeNameArray = [ed_pchsClntNo, txt_pchsClntNm]; // 협력회사코드, 협력회사명
            break;

        case 2:
            // 매입부서 팝업
            comCodeComp = udc_pchsDept;
            selectedId = 'retrieveLobranInfo';
            codeNameArray = [ed_pchsDeptCd, txt_pchsDeptNm]; // 점소코드, 점소명
            break;

        case 3:
            // 모선 팝업
            comCodeComp = udc_coshipvssl;
            selectedId = 'retrieveVsslCdInfo';
            codeNameArray = [ed_coshipvsslCd, ed_coshipvsslNm]; // 모선코드, 모선명
            break;

        case 4:
            // 작업장 팝업
            comCodeComp = udc_wrkPl;
            selectedId = 'retrieveWrkPlInfo';
            codeNameArray = [ed_wrkPlCd, txt_wrkPlNm]; // 작업장코드, 작업장명
            break;

        default:
            break;
    };


    comCodeComp.setSelectId(selectedId);

    comCodeComp.cfCommonPopUp(
        (rtnList) => {
            $c.gus.cfSetReturnValue(rtnList, codeNameArray[0], codeNameArray[1]);
        },
        pCode.trim(),
        pName,
        pClose,
        pDispCnt,
        pTitle,
        pWidth,
        pHidden,
        pWhere,
        pW,
        pH,
        pTop,
        pLeft,
        pExistTF,
        pAllSearch,
        pWtitleSearch,
        pNoDataCloseTF
    );

};



/**
 * @method 
 * @name f_openCommonPopUp 
 * @description 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
 * @param {object} inObj
 * @param {object} pairObj
 * @param {number} disGubun
 * @param {string} isCode
 */
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = inObj.getValue();

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};



