/**
 * @event 
 * @name sbm_purchaseListQueryConditionDTO_submit 
 * @description 작업도구임차료목록 조회 요청전
 */
scwin.sbm_purchaseListQueryConditionDTO_submit = function (e) {

    let jsonData = dma_purchaseListQueryConditionDTO.getJSON();

    jsonData.pchsClntNo = ed_pchsClntNo.getValue(); //매입거래처번호
    jsonData.pchsDeptCd = ed_pchsDeptCd.getValue(); //물류점소
    jsonData.coshipVsslCd = ed_coshipvsslCd.getValue(); //모선
    jsonData.coshipPortcnt = ed_coshipPortcnt.getValue(); //항차
    jsonData.wrkPlCd = ed_wrkPlCd.getValue(); //작업장
    jsonData.wrkImpleKndCd = acb_wrkImpleKndCd.getValue(); //작업도구종류코드
    jsonData.dtCls = acb_dtCls.getValue(); //일자구분(작업일자/확인일자)
    jsonData.wrkDtSt = ed_wrkDtSt.getValue(); //작업일자시작
    jsonData.wrkDtEnd = ed_wrkDtEnd.getValue(); //작업일자종료
    jsonData.copCoConfirmDtSt = ed_copCoConfirmDtSt.getValue(); //협력업체확인일자시작
    jsonData.copCoConfirmDtEnd = ed_copCoConfirmDtEnd.getValue(); //협력업체확인일자종료
    jsonData.copCoConfirmClsCd = acb_copCoConfirmClsCd.getValue(); //협력업체확인구분코드
    jsonData.pchsAdmitClsCd = acb_pchsAdmitClsCd.getValue(); //매입승인구분코드
    jsonData.unconfirmedIncluYn = cbx_unconfirmedIncluYn.getValue(); //미확인포함여부
    jsonData.unAdmitIncluYn = cbx_unAdmitIncluYn.getValue(); //미승인포함여부 

    dma_purchaseListQueryConditionDTO.setJSON(jsonData);

};


/**
 * @event 
 * @name sbm_purchaseListQueryConditionDTO_submitdone 
 * @description 작업도구임차료목록 조회 정상
 */
scwin.sbm_purchaseListQueryConditionDTO_submitdone = function (e) {

    if (e.responseJSON.resultDataSet[0].Code == -1) return;

    // 총 조회건수 표시
    let rowCnt = ds_workImplementLoanChargeList.getRowCount();
    totalRows.setValue(rowCnt);

    // 건수/총금액 계산
    scwin.f_GetConfirmCntTotAmt();

    gr_workImplementLoanChargeList.setHeaderValue('chkHeader', false);

    if (rowCnt == 0) {
        $c.gus.cfDisableAllBtn();
        $c.gus.cfDisableObjects([ica_allCopCoConfirmDt]);
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
    } else {
        $c.gus.cfEnableAllBtn();
        $c.gus.cfEnableObjects([ica_allCopCoConfirmDt]);
    };

};



/**
 * @event 
 * @name sbm_saveCooperationCompanyConfirmation_submitdone 
 * @description 컨테이너하불확인 저장 정상
 */
scwin.sbm_saveCooperationCompanyConfirmation_submitdone = function (e) {

    if (e.responseJSON.resultDataSet[0].Code == -1) return;

    scwin.f_RetrieveWorkImplementLoanChargeList();
    $c.gus.cfAlertMsg(MSG_CM_INF_001);	 // 성공적으로 저장하였습니다

};






