/**
 * @event 
 * @name acb_dtCls_onchange 
 * @description 조회조건(작업일자 / 확인일자) 선택
 * @param {object} info
 * @param {String} info.oldValue
 * @param {String} info.newValue
 * @param {Number} info.oldSelectedIndex
 * @param {Number} info.newSelectedIndex
 */
scwin.acb_dtCls_onchange = function (info) {

    switch (info.newValue) {
        case '01': scwin.f_SelWrkDt(); break;
        case '02': scwin.f_SelCopCoConfirmDt(); break;
        default: break;
    };

};



/**
 * @event 
 * @name gr_workImplementLoanChargeList_oncellclick 
 * @description 셀이 클릭된 경우 발생
 * @param {Number} rowIndex
 * @param {Number} columnIndex
 * @param {String} columnId
 */
scwin.gr_workImplementLoanChargeList_oncellclick = function (rowIndex, columnIndex, columnId) {

    let rowData = ds_workImplementLoanChargeList.getRowJSON(rowIndex);
    let btn = rowData.btn;
    let copCoConfirmClsCd = rowData.copCoConfirmClsCd;

    switch (columnId) {
        case 'copCoConfirmDt':
            // 확인
            if (btn == "T" && copCoConfirmClsCd != "03") {
                gr_workImplementLoanChargeList.setColumnReadOnly('copCoConfirmDt', false);
            } else {
                gr_workImplementLoanChargeList.setColumnReadOnly('copCoConfirmDt', true);
            };

            // 미확인
            if (btn == "T" && copCoConfirmClsCd == "01") {
                gr_workImplementLoanChargeList.setColumnReadOnly('copCoConfirmDt', true);
            };
            break;

        case 'dissent':
            // 이의처리/보류사유
            if (btn == "T" && copCoConfirmClsCd == "03") {
                gr_workImplementLoanChargeList.setColumnReadOnly('dissent', false);
            } else {
                gr_workImplementLoanChargeList.setColumnReadOnly('dissent', true);
            };

            // 이의신청 이력 수정
            if (rowData.dissent != "") {
                scwin.f_RetrieveDissentApplyHistory(rowIndex);
            };
            break;

        default:
            break;
    };

};



/**
 * @event 
 * @name gr_workImplementLoanChargeList_oneditend 
 * @description 셀이 클릭된 경우 발생
 * @param {Number} rowIndex
 * @param {Number} columnIndex
 * @param {String} value
 */
scwin.gr_workImplementLoanChargeList_oneditend = function (rowIndex, columnIndex, value) {

    let colId = gr_workImplementLoanChargeList.getColumnID(columnIndex);
    if (colId != "copCoConfirmDt") return;

    // 확인 날짜입력시 validation 체크
    let olddata = ds_workImplementLoanChargeList.getCellData(rowIndex, "copCoConfirmDt");
    if ($c.num.isNumber(value)) {
        if (!$c.date.isDate(value, false)) {
            $c.gus.cfAlertMsg("확인일자는 'YYYYMMDD' 형식이어야 합니다.");
            return;
        };
    } else {
        ds_workImplementLoanChargeList.setCellData(rowIndex, "copCoConfirmDt", olddata);
        $c.gus.cfAlertMsg("확인일자를 다시 입력하십시오.");
        return;
    };

};



